import { Client } from "@notionhq/client"
import { config } from "dotenv"

config()

const NOTION_API_KEY = process.env.NOTION_API_KEY!
const DATABASE_ID = process.env.NOTION_DATABASE_ID!

if (!NOTION_API_KEY || !DATABASE_ID) {
  console.error("NOTION_API_KEY and NOTION_DATABASE_ID must be set in .env")
  process.exit(1)
}

const notion = new Client({ auth: NOTION_API_KEY })

interface DataSource {
  id: string
  name: string
}

async function main() {
  try {
    // 데이터베이스 조회 → data_sources 목록 획득
    const database = await notion.request({
      method: "get",
      path: `databases/${DATABASE_ID}`,
    }) as { id: string; data_sources: DataSource[] }

    console.log("Database:", database.id)
    console.log("Data sources:", database.data_sources)

    // 첫 번째 data source의 스키마(properties) 조회
    const dataSource = database.data_sources[0]
    const schema = await notion.request({
      method: "get",
      path: `data_sources/${dataSource.id}`,
    }) as { id: string; properties: Record<string, unknown> }

    console.log("Properties:", Object.keys(schema.properties))

    // data source에서 페이지 쿼리
    const query = await notion.request({
      method: "post",
      path: `data_sources/${dataSource.id}/query`,
    }) as { results: Array<{ id: string }> }

    console.log("Results:", query.results.length, "pages")

    // 각 페이지의 블록(내용) 조회
    for (const page of query.results) {
      console.log("\n--- Page:", page.id, "---")

      const blocks = await notion.request({
        method: "get",
        path: `blocks/${page.id}/children`,
      }) as { results: Array<{ id: string; type: string; [key: string]: unknown }> }

      for (const block of blocks.results) {
        const data = block[block.type] as { rich_text?: Array<{ plain_text: string }> } | undefined
        const text = data?.rich_text?.map((t) => t.plain_text).join("") ?? ""
        console.log(`[${block.type}]`, text)
      }
    }
  } catch (error) {
    console.error(error)
  }
}

main()

